'use client';

import { useActionState } from 'react';
import { createPost } from './actions';

const initialState = {
  message: ''
};

export default function Home() {
  const [state, action, pending] = useActionState(createPost, initialState);

  return (
    <main>
      <h1>Posts</h1>
      <form action={action}>
        <label htmlFor="title">Title</label>
        <input id="title" name="title" placeholder="New post title" required />
        <button type="submit" disabled={pending}>
          {pending ? 'Creating...' : 'Create post'}
        </button>
      </form>
      {state.message ? <p aria-live="polite">{state.message}</p> : null}
    </main>
  );
}
EOF

cat > app/actions.ts <<'EOF'
'use server';

import { revalidateTag } from 'next/cache';

export async function createPost(
  _prevState: { message: string },
  formData: FormData
): Promise<{ message: string }> {
  const title = String(formData.get('title') ?? '').trim();

  if (!title) {
    return { message: 'Title is required.' };
  }

  // Replace this with your persistence logic.
  // After creating the post, invalidate the cache tag so the next page load
  // waits for fresh data rather than serving stale cached content.
  revalidateTag('posts', 'max');

  return { message: `Created post: ${title}` };
}
EOF

